xpath.script:
(function() {
    var STORAGE_KEY = 'wl_page_agent_history';
    var H = '_1tu05_'; // CSS module hash

    function applyStyles() {
        var bg = document.querySelector('[class*="_background' + H + '"]');
        if (bg) {
            bg.style.setProperty('background', 'linear-gradient(135deg,rgba(90,8,14,0.97),rgba(122,12,20,0.97))', 'important');
            bg.style.setProperty('border-radius', '12px', 'important');
            bg.style.setProperty('box-shadow', '0 8px 32px rgba(90,8,14,0.3)', 'important');
        }
        var hist = document.querySelector('[class*="_historySectionWrapper' + H + '"]');
        if (hist) hist.style.setProperty('background', 'rgba(90,8,14,0.85)', 'important');
        var header = document.querySelector('[class*="_header' + H + '"]');
        if (header) header.style.setProperty('background', 'rgba(90,8,14,0.6)', 'important');
        var st = document.querySelector('[class*="_statusText' + H + '"]');
        if (st) {
            st.style.setProperty('color', '#f5c400', 'important');
            st.style.setProperty('font-weight', '600', 'important');
        }
        var ind = document.querySelector('[class*="_indicator' + H + '"]');
        if (ind) ind.style.setProperty('background', '#f5c400', 'important');
        var isw = document.querySelector('[class*="_inputSectionWrapper' + H + '"]');
        if (isw) isw.style.setProperty('background', 'rgba(253,251,245,0.95)', 'important');
        var input = document.querySelector('[class*="_taskInput' + H + '"]');
        if (input) {
            input.style.setProperty('background', '#fff', 'important');
            input.style.setProperty('color', '#1f1f1f', 'important');
            input.style.setProperty('border', '1px solid #ddd', 'important');
            input.style.setProperty('border-radius', '8px', 'important');
            input.style.setProperty('font-size', '13px', 'important');
            input.style.setProperty('padding', '8px 12px', 'important');
            input.style.setProperty('font-family', 'Inter,-apple-system,sans-serif', 'important');
            if (input.placeholder && /[\u4e00-\u9fff]/.test(input.placeholder)) {
                input.placeholder = 'Tulis perintah... (contoh: pesan seblak)';
            }
        }
        var btns = document.querySelectorAll('[class*="_controlButton' + H + '"]');
        btns.forEach(function(b) {
            if (b.className.indexOf('_stopButton') < 0) {
                b.style.setProperty('background', 'rgba(245,196,0,0.15)', 'important');
                b.style.setProperty('color', '#f5c400', 'important');
                b.style.setProperty('border-radius', '6px', 'important');
            }
        });
    }

    function fixText() {
        var input = document.querySelector('[class*="_taskInput' + H + '"]');
        if (input && input.placeholder && /[\u4e00-\u9fff]/.test(input.placeholder)) {
            input.placeholder = 'Tulis perintah... (contoh: pesan seblak)';
        }
        var wrapper = document.querySelector('[class*="_wrapper' + H + '"]');
        if (!wrapper) return;
        var walker = document.createTreeWalker(wrapper, NodeFilter.SHOW_TEXT, null);
        var node;
        while (node = walker.nextNode()) {
            var t = node.textContent;
            if (t.indexOf('\u51c6\u5907\u5c31\u7eea') >= 0) node.textContent = node.textContent.replace(/\u51c6\u5907\u5c31\u7eea/g, 'Siap');
            if (t.indexOf('\u7b49\u5f85\u4efb\u52a1') >= 0) node.textContent = node.textContent.replace(/\u7b49\u5f85\u4efb\u52a1\u5f00\u59cb[^]*/g, 'Menunggu tugas...');
            if (t.indexOf('\u6b63\u5728\u601d\u8003') >= 0) node.textContent = node.textContent.replace(/\u6b63\u5728\u601d\u8003[^]*/g, 'Sedang berpikir...');
            if (t.indexOf('\u6b63\u5728\u6267\u884c') >= 0) node.textContent = node.textContent.replace(/\u6b63\u5728\u6267\u884c[^]*/g, 'Sedang menjalankan...');
            if (t.indexOf('\u4efb\u52a1\u5b8c\u6210') >= 0) node.textContent = node.textContent.replace(/\u4efb\u52a1\u5b8c\u6210/g, 'Tugas selesai');
            if (t.indexOf('\u4efb\u52a1\u5df2\u505c\u6b62') >= 0) node.textContent = node.textContent.replace(/\u4efb\u52a1\u5df2\u505c\u6b62/g, 'Tugas dihentikan');
            if (t.indexOf('\u51fa\u73b0\u9519\u8bef') >= 0) node.textContent = node.textContent.replace(/\u51fa\u73b0\u9519\u8bef/g, 'Terjadi kesalahan');
        }
    }

    function setupAgent() {
        var pa = window.pageAgent;
        if (!pa || pa.disposed) return false;
        try {
            pa.config.language = 'id-ID';
            if (pa.config.pageController && pa.config.pageController.config) {
                pa.config.pageController.config.language = 'id-ID';
            }
        } catch(e) {}
        try {
            var saved = sessionStorage.getItem(STORAGE_KEY);
            if (saved) {
                var h = JSON.parse(saved);
                if (Array.isArray(h) && h.length > 0) pa.history = h;
            }
        } catch(e) {}
        try {
            pa.addEventListener('message', function() {
                try { if (pa.history && pa.history.length > 0) sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history)); } catch(e) {}
            });
        } catch(e) {}
        window.addEventListener('beforeunload', function() {
            try { if (pa.history && pa.history.length > 0) sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history)); } catch(e) {}
        });
        return true;
    }

    // Apply styles + fix text on interval (60 seconds)
    var attempts = 0;
    var interval = setInterval(function() {
        attempts++;
        applyStyles();
        fixText();
        if (window.pageAgent && !window.pageAgent.disposed) setupAgent();
        if (attempts >= 120) clearInterval(interval);
    }, 500);

    // MutationObserver: re-apply on ANY DOM change (indefinite)
    var observer = new MutationObserver(function() {
        applyStyles();
        fixText();
    });
    if (document.body) {
        observer.observe(document.body, { childList: true, subtree: true, characterData: true });
    }
})();
